  const data = dataTool.run()
  if (!dataFresh(data)) { dataTool.refresh() }
  const risk = riskTool.run(data)
  const analysis = analyticsTool.run(data, risk)
  if (shouldAlert(analysis)) alertTool.run(analysis)
  sleep(Δt)
