function attention(q, K, V) {
  // q: 1xd, K: nxd, V: nxd
  const dk = q.length;
  const scores = K.map(k => dot(q, k) / Math.sqrt(dk));
  const weights = softmax(scores);
  const out = [0,0].map((_,i) => weights.reduce((acc, w, idx) => acc + w * V[idx][i], 0));
