// Skeleton: per-type chunk sizes and basic chunking hook
const CHUNK_SPECS = { api: 512, policy: 1024, incident: 1024 };
function chunkDocument(doc){
  const max = CHUNK_SPECS[doc.type] ?? 512;
  // simple approach: split into sentences then group by max tokens
  const sentences = splitIntoSentences(doc.text);
  const chunks = [];
  let cur = '';
  for (const s of sentences){
    if ((cur + s).length > max){ chunks.push(cur.trim()); cur = s; }
    else { cur += s; }
  }
  if (cur) chunks.push(cur.trim());
  return chunks;
}
```

