## Code Example
```typescript
function chunkDocument(text: string, maxTokens: number = 500) {
  const sections = text.split(/\n(?=#{1,3}\s)/); // Split by headers
  const chunks = [];

  for (const section of sections) {
    const sentences = section.split('. ');
    let currentChunk = '';

    for (let i = 0; i < sentences.length; i++) {
      const testChunk = currentChunk + sentences[i] + '. ';
      if (countTokens(testChunk) > maxTokens) {
        chunks.push(currentChunk.trim());
        currentChunk = sentences[i - 2] + '. ' + sentences[i - 1] + '. '; // Overlap
      } else {
        currentChunk = testChunk;
      }
    }
    chunks.push(currentChunk.trim());
  }
  return chunks;
}
```

